function makeContext() {
  const ctx = {
    console,
    setTimeout,
    setInterval,
    clearTimeout,
    clearInterval,
    performance,
    Math,
    Date,
  };
  // window alias
  ctx.window = {};
  // requestAnimationFrame: call cb async with timestamp
  ctx.requestAnimationFrame = function(cb) { return setTimeout(() => cb(performance.now()), 0); };
  return ctx;
}

